proof fn phi_5_get_proc_container_dom_only_under_full_wf(
    pm: ProcessManager,
    p_ptr: ProcPtr,
)
    requires
        pm.proc_perms_wf(),
        pm.process_fields_wf(),
        pm.proc_dom().contains(p_ptr),
        !pm.wf(),
    ensures
        true,
{
    // Under these weaker preconditions, get_proc does NOT ensure
    // container_dom().contains(ret.owning_container) — the implication
    // is guarded by self.wf(). This means callers using get_proc
    // without full wf() can obtain a process whose owning_container
    // is not in the container domain.
